    private static final long serialVersionUID = 9057165148930624087L;

    public Object answer(InvocationOnMock invocation) throws Throwable {
        Method method = invocation.getMethod();
        if ((method.getModifiers() & Modifier.ABSTRACT) != 0) {
            // Return default value for abstract methods since they have no implementation
            return defaultValueFor(method.getReturnType());
        }
        return invocation.callRealMethod();
    }

    private Object defaultValueFor(Class<?> type) {
        if (type == boolean.class) return false;
        if (type == byte.class) return (byte) 0;
        if (type == char.class) return (char) 0;
        if (type == double.class) return 0.0;
        if (type == float.class) return 0.0f;
        if (type == int.class) return 0;
        if (type == long.class) return 0L;
        if (type == short.class) return (short) 0;
        // For all reference types including void, return null
        return null;
    }
}

